// Emit API v2: emit(event) where event is { type, payload }.
// Stores the event and dispatches to the matching registered handler.
const { make } = require("./event.js");
const { Store } = require("./store.js");
const { all } = require("./index.js");

const store = new Store();

function emit(event) {
  const made = make(event.type, event.payload);
  store.add(made);
  const handler = all().find((h) => h.type === made.type);
  if (!handler) {
    throw new Error(`no handler for type: ${made.type}`);
  }
  return handler.handle(made);
}

module.exports = { emit, store };

const { emit } = require("../emit.js");
module.exports = {
  a: (x) => emit({ type: "ping", payload: { n: x } }),
  b: (x) => emit({ type: "ping", payload: { n: x * 2 } }),
};

